async function pMap(items, fn, concurrency = 5) {
  const results = [];
  const active = new Set();
  for (const [i, item] of items.entries()) {
    const p = fn(item).then(val => {
      active.delete(p);
      return val;
    });
    active.add(p);
    results[i] = p;
    if (active.size >= concurrency) {
      await Promise.race(active);
    }
  }
  return Promise.all(results);
}

